// Load JWT SECRET and API token
const SECRET = global.get('JWT_SECRET'); 
const API_KEY = env.get("API_KEY");
const TOKEN_COOKIE_NAME = 'auth_token';

// Initialization
let isAuthorized = false;
let authMessage = "Missing Authorization (Neither Bearer Token nor JWT Cookie found)"; // Default message, no token or JWT provided
let token = null;


// First, try API token
const authHeader = msg.req.headers.authorization;

if (API_KEY && authHeader && authHeader.startsWith('Bearer ')) {
    const receivedKey = authHeader.substring(7).trim();

    if (receivedKey === API_KEY) {
        // API key is valid
        isAuthorized = true;
    } else {
        authMessage = "Invalid Bearer Token (API Key)";
    }
}

// Second, try JWT cookie
if (!isAuthorized) {
    token = msg.req.cookies ? msg.req.cookies[TOKEN_COOKIE_NAME] : null;

    if (token) {
        // Only now do we care if the SECRET exists
        if (!SECRET) {
            node.warn("JWT Secret is missing, but a cookie was presented.");
            authMessage = "Server configuration error: JWT Secret missing.";
        } else {
            try {
                // Verify JWT token
                jsonwebtoken.verify(token, SECRET);
                isAuthorized = true;
            } catch (err) {
                // Invalidate the cookie if not valid
                const deleteCookie = `${TOKEN_COOKIE_NAME}=; Path=/; HttpOnly; Secure; Max-Age=0`;
                msg.headers = { 'Set-Cookie': deleteCookie };
                authMessage = `JWT Error: ${err.message}`;
            }
        }
    }
}

if (isAuthorized) {

    // Set headers 
    msg.headers = { 
        'Cache-Control': 'no-cache, no-store, must-revalidate',
        'Pragma': 'no-cache',
        'Expires': '0',
        'X-Content-Type-Options': 'nosniff',
        'X-Frame-Options': 'DENY'
    };

    return [msg, null];

} else {

    // Unauthorized
    msg.statusCode = 401;
    msg.headers = {
        'Cache-Control': 'no-store',
        ...(msg.headers || {}) 
    };

    msg.payload = {
        success: false,
        message: authMessage 
    };

    return [null, msg];
}

const USERNAME = env.get("Username");
const PASSWORD = env.get("Password");
const SECRET = global.get('JWT_SECRET');
const REDIRECT_URL = env.get("Redirect"); 

// Check basic variables for authentication
if (!USERNAME || !PASSWORD || !SECRET || !REDIRECT_URL) { 
    node.warn("Subflow is not properly configured. Username, password and redirect must be set");
    msg.statusCode = 500;
    msg.payload = {
        success: false,
        message: "Flow configuration error, please check if username, password and redirect are set"
    };
    return msg;
}

// Get auth header
const authHeader = msg.req.headers.authorization;

// Basic auth
if (!authHeader || !authHeader.startsWith('Basic ')) {
    msg.statusCode = 401;
    msg.headers = { 'WWW-Authenticate': 'Basic realm="Secure Area"' };
    msg.payload = {
        success: false,
        message: "Authentication Required"
    };
    return msg;
}

// Extract and decode the username and password
const encoded = authHeader.substring(6);
const [clientUsername, clientPassword] = Buffer.from(encoded, 'base64').toString().split(':');

// Verify the username and password
if (clientUsername === USERNAME && clientPassword === PASSWORD) {

    const payload = {
        sub: clientUsername,
        id: 1,
        role: 'system_client'
    };

    // Sign JWT token
    const token = jsonwebtoken.sign(payload, SECRET, { expiresIn: '1h' });

    // Set JWT token as cookie
    msg.cookies = {
        auth_token: {
            value: token,
            maxAge: 3600000,
            httpOnly: true,
            secure: true,
            sameSite: 'Strict',
            path: '/'
        }
    }

    // Redirect browser
    msg.statusCode = 302;
    msg.headers = {
        'Location': REDIRECT_URL
    };

    return msg;

}

// Wrong username or password
else {
    msg.statusCode = 401;
    msg.headers = { 'WWW-Authenticate': 'Basic realm="Secure Area"' };
    msg.payload = {
        success: false,
        message: "Invalid Credentials"
    };
    return msg;
}

