const requiredFields = ['companyId', 'clientId', 'clientSecret'];
const missingFields = [];


if (!msg.payload) {
    node.error("Chybí msg.payload", msg);
    return null; // Zastaví flow
}

requiredFields.forEach(field => {
    if (!msg.payload[field]) {
        missingFields.push(field);
    }
});

if (missingFields.length > 0) {
    node.error(`Chybějící parametry pro Sloneek login: ${missingFields.join(', ')}`, msg);
    return null;
}

msg.companyName = msg.payload.name
msg.companyId = msg.payload.companyId;
msg.method = "POST";
msg.url = `https://api2.sloneek.com/auth/client-credential-login`;

msg.payload = {
    client_id: msg.payload.clientId,
    client_secret: msg.payload.clientSecret
};

return msg;

if (msg.companyId === undefined || msg.companyId === null) {
    return null;
}

if (typeof msg.createMissing !== "boolean") {
    return null;
}

const tokens = flow.get("access_tokens") || [];
const entry = tokens.find(item => item.companyId == msg.companyId);

if (entry && entry.access_token) {
    msg.token = entry.access_token;
    msg.method = "GET";
    msg.headers = {
        "Authorization": `Bearer ${msg.token}`,
        "Content-Type": "application/json"
    };

    const page = msg.page || 1;
    msg.url = `https://api2.sloneek.com/colleagues/paginated-v2?pivotMode=false&page=${page}`;

    return msg;
} else {
    return null;
}

const response = msg.payload;
const statusCode = msg.payload.status_code
const errorMessage = response.message;

if (statusCode !== 200) {
    msg.detail = `User import failed: \n\nCompany: ${msg.companyName} (${msg.companyId}) \n\nMessage: ${errorMessage} \n\nStatus code: ${statusCode}`;
    node.error(`${statusCode}: ${errorMessage}`, msg);
    return; 
}

const data = response.data;

if (msg.allUsers === undefined) {
    msg.allUsers = [];
}

if (data.items && Array.isArray(data.items)) {
    msg.allUsers = msg.allUsers.concat(data.items);
}

if (data.next_page !== null && data.next_page !== undefined) {
    msg.page = data.next_page;
    return [null, msg]; 
} else {
    msg.payload = msg.allUsers;
    msg.total_collected = msg.allUsers.length;
    return [msg, null];
}

msg.fullName = msg.name + " " + msg.surname;
msg.query = `?filter={"$and": [{"Account.Email": {"$eq": "${msg.email}"}},{"Company.Id": {"$in": [${msg.companyId}]}},{"IsVisitor": {"$eq": false}}]}`
return msg;

const items = msg.payload;
const createMissing = msg.createMissing;

const isEmpty = !items ||
    (Array.isArray(items) && items.length === 0) ||
    (typeof items === 'object' && Object.keys(items).length === 0);

if (isEmpty) {
    if (createMissing === false) {
        return [null, null];
    } else {
        msg.body = {
            "Name": msg.fullName,
            "Account": { "Email": msg.email },
            "Company": { "Id": msg.companyId },
            "Integration": { "ExternalId": msg.externalId }
        }
        return [msg, null];
    }
} else {
    msg.userId = (items[0] && items[0].Id) ? items[0].Id : null;
    msg.body = [{ "op": "replace", "path": "/Integration/ExternalId", "value": msg.externalId }]
    return [null, msg];
}

const tokens = flow.get("access_tokens") || [];

const entry = tokens.find(item => item.companyId == msg.companyId);

if (entry && entry.access_token) {
    msg.token = entry.access_token;
    msg.method = "POST";
    msg.headers = {
        "Authorization": `Bearer ${msg.token}`
    };
    if (msg.direction == "Entry") {
        msg.url = `https://api2.sloneek.com/v1/module-attendance-v2/attendance-segment-event`;
        msg.payload = {
            user_uuid: msg.externalId
        }
    }
    else if (msg.direction == "Exit") {
        msg.url = `https://api2.sloneek.com/v1/module-attendance-v2/attendance-segment-event/close`;
        msg.payload = {
            user_uuid: msg.externalId
        }
    }
    return msg;
}

if (msg.direction === "Exit") {
    msg.detail = `Failed to clock out user: 

${msg.userName} (${msg.userId}) 

Message: ${msg.payload.message} 

Status code: ${msg.payload.status_code}`;
    return msg;
} else if (msg.direction === "Entry") {
    msg.detail = `Failed to clock in user: 

${msg.userName} (${msg.userId})

Message: ${msg.payload.message} 

Status code: ${msg.payload.status_code}`;
    return msg;
}

const configs = Array.isArray(msg.payload) ? msg.payload : [];

msg.payload = configs.map(item => ({
    ...item,
    clientSecret: "********"
}));

return msg;

const rawData = msg.payload;
let errors = [];

const allowedKeys = ["companyId", "name", "clientId", "clientSecret", "syncPolicy"];

const cleanConfig = {};

allowedKeys.forEach(key => {
    if (rawData[key] !== undefined && rawData[key] !== null && rawData[key] !== "") {
        cleanConfig[key] = rawData[key];
    } else {
        errors.push(`Missing or empty field: ${key}`);
    }
});

if (cleanConfig.syncPolicy) {
    const policy = cleanConfig.syncPolicy;
    cleanConfig.syncPolicy = {
        createMissingUsers: typeof policy.createMissingUsers === 'boolean' ? policy.createMissingUsers : false
    };
}

if (errors.length > 0) {
    msg.payload = {
        status: "error",
        message: "Validation failed - mandatory fields missing",
        required: errors
    };
    msg.statusCode = 400;
    return [null, msg];
}

msg.config = cleanConfig;

return [msg, null];

const newEntry = msg.config;
const existingData = Array.isArray(msg.payload) ? msg.payload : [];

const alreadyExists = existingData.some(item => item.companyId === newEntry.companyId);

if (alreadyExists) {
    msg.payload = {
        error: "Conflict",
        message: `Configuration for companyId ${newEntry.companyId} already exists.`
    };
    msg.statusCode = 409;
    return [null, msg];
}

existingData.push(newEntry);

msg.payload = existingData;

return [msg, null];

const targetId = parseInt(msg.companyId);
const existingData = msg.payload;

if (!Array.isArray(existingData)) {
    msg.payload = { error: "Configuration file is empty or corrupted." };
    msg.statusCode = 404;
    return [null, msg];
}

const initialLength = existingData.length;
const updatedData = existingData.filter(item => item.companyId !== targetId);

if (updatedData.length === initialLength) {
    msg.payload = {
        status: "error",
        message: `Configuration with companyId ${targetId} not found.`
    };
    msg.statusCode = 404;
    return [null, msg];
}

msg.payload = updatedData;

return [msg, null];

const tokens = flow.get("access_tokens") || [];

const entry = tokens.find(item => item.companyId == msg.companyId);

if (entry && entry.access_token) {
    msg.token = entry.access_token;
    msg.method = "POST";
    msg.headers = {
        "Authorization": `Bearer ${msg.token}`
    };
    if (msg.direction == "Entry") {
        msg.url = `https://api2.sloneek.com/v1/module-attendance-v2/attendance-segment-event`;
        msg.payload = {
            user_uuid: msg.externalId
        }
    }
    else if (msg.direction == "Exit") {
        msg.url = `https://api2.sloneek.com/v1/module-attendance-v2/attendance-segment-event/close`;
        msg.payload = {
            user_uuid: msg.externalId
        }
    }
    return msg;
}

msg.detail = `Connection with Sloneek failed: 

Company: ${msg.companyName} (${msg.companyId}) 

Message: ${msg.payload.message} 

Status code: ${msg.payload.status_code}`;
return msg;

msg.host = msg.payload?.IpAddress || "ip_address";

const baseUrl = `https://${msg.host}/nodered`;

const path = "/api/sloneek/setup"

const setupUrl = baseUrl + path

node.status({
    fill: "blue",
    shape: "dot",
    text: path
});

msg.payload = setupUrl

